// MetadataServiceServer is the server API for MetadataService service.
// All implementations should embed UnimplementedMetadataServiceServer
// for forward compatibility
type MetadataServiceServer interface {
	// Repositories
	CreateRepository(context.Context, *CreateRepositoryRequest) (*Repository, error)
	GetRepository(context.Context, *GetRepositoryRequest) (*Repository, error)
	GetRepositoryByName(context.Context, *GetRepositoryByNameRequest) (*Repository, error)
	ListRepositories(*ListRepositoriesRequest, MetadataService_ListRepositoriesServer) error
	DeleteRepository(context.Context, *DeleteRepositoryRequest) (*emptypb.Empty, error)
	UpdateRepositoryQuota(context.Context, *UpdateRepositoryQuotaRequest) (*Repository, error)
	UpdateRepository(context.Context, *UpdateRepositoryRequest) (*Repository, error)
	// Tag immutability (futures.md Tier 1 #2) — flips the repo-wide
	// `immutable_tags` flag. Separate RPC from UpdateRepository so the
	// audit trail records the security-relevant change explicitly
	// (description edits stay on the existing path).
	UpdateRepositoryImmutability(context.Context, *UpdateRepositoryImmutabilityRequest) (*Repository, error)
	// Signed-image admission (futures.md Tier 1 #3) — flips the repo-wide
	// `require_signature` flag. Separate RPC from UpdateRepository for
	// the same audit-trail-clarity reason as UpdateRepositoryImmutability.
	UpdateRepositorySignaturePolicy(context.Context, *UpdateRepositorySignaturePolicyRequest) (*Repository, error)
	// FUT-021 — CVSS-gated admission policy. Flips the repo-wide
	// `max_cvss_score` threshold. Nullable Int32Value: null clears the
	// gate (no threshold enforced); a value 0-100 sets the threshold at
	// which services/core will refuse pulls whose top scan CVSS score
	// exceeds it. Same audit-trail-clarity reasoning as
	// UpdateRepositorySignaturePolicy — dedicated RPC so the security-
	// relevant transition is easy to spot in the audit log.
	UpdateRepositoryCVSSPolicy(context.Context, *UpdateRepositoryCVSSPolicyRequest) (*Repository, error)
	// Signed-image admission Phase 2 (futures.md Tier 1 #3) — per-repo
	// trusted-key allowlist. When `require_signature=true` AND the list
	// is non-empty, services/core narrows the admission gate to only
	// signatures produced by an allowed key_id. Empty list falls back
	// to Phase 1 "ANY signature passes" so operators can flip the flag
	// first and pin keys incrementally.
	ListRepositoryTrustedKeys(context.Context, *ListRepositoryTrustedKeysRequest) (*ListRepositoryTrustedKeysResponse, error)
	AddRepositoryTrustedKey(context.Context, *AddRepositoryTrustedKeyRequest) (*RepositoryTrustedKey, error)
	RemoveRepositoryTrustedKey(context.Context, *RemoveRepositoryTrustedKeyRequest) (*emptypb.Empty, error)
	// Tags
	PutTag(context.Context, *PutTagRequest) (*Tag, error)
	GetTag(context.Context, *GetTagRequest) (*Tag, error)
	ListTags(*ListTagsRequest, MetadataService_ListTagsServer) error
	DeleteTag(context.Context, *DeleteTagRequest) (*emptypb.Empty, error)
	// Tag immutability pin (futures.md Tier 1 #2) — flips the per-tag
	// `immutable` flag. Returns the updated Tag so the caller (FE,
	// promotion workflow) can confirm without a follow-up GetTag.
	UpdateTagImmutable(context.Context, *UpdateTagImmutableRequest) (*Tag, error)
	// Manifests
	PutManifest(context.Context, *PutManifestRequest) (*Manifest, error)
	GetManifest(context.Context, *GetManifestRequest) (*Manifest, error)
	DeleteManifest(context.Context, *DeleteManifestRequest) (*emptypb.Empty, error)
	// FE-API-050 — set / clear quarantine on a manifest. Called by the
	// scanner after a scan that violates the effective block_on_severity
	// policy (quarantined=true), and by services/management when an
	// operator manually quarantines or lifts via the dashboard.
	// Idempotent: re-applying quarantine=true keeps the existing
	// quarantined_at + quarantined_by (the FIRST event is the
	// load-bearing one for audit). quarantined=false clears all four
	// columns.
	UpdateManifestQuarantine(context.Context, *UpdateManifestQuarantineRequest) (*Manifest, error)
	ListUntaggedManifests(*ListUntaggedManifestsRequest, MetadataService_ListUntaggedManifestsServer) error
	// Blobs
	LinkBlob(context.Context, *LinkBlobRequest) (*emptypb.Empty, error)
	UnlinkBlob(context.Context, *UnlinkBlobRequest) (*emptypb.Empty, error)
	ListOrphanedBlobs(*ListOrphanedBlobsRequest, MetadataService_ListOrphanedBlobsServer) error
	// Quota
	GetTenantQuotaUsage(context.Context, *GetTenantQuotaUsageRequest) (*QuotaUsage, error)
	UpdateTenantQuota(context.Context, *UpdateTenantQuotaRequest) (*QuotaUsage, error)
	IncrementTenantStorage(context.Context, *IncrementTenantStorageRequest) (*emptypb.Empty, error)
	DecrementTenantStorage(context.Context, *DecrementTenantStorageRequest) (*emptypb.Empty, error)
	// Scan status
	UpdateScanStatus(context.Context, *UpdateScanStatusRequest) (*emptypb.Empty, error)
	GetScanResult(context.Context, *GetScanResultRequest) (*ScanResult, error)
	// Per-tag SBOM storage (FE-API-033). The SBOM is persisted on the
	// scan_results row keyed by (tenant_id, manifest_digest); the management
	// BFF exposes a tag-scoped download route on top.
	//
	// UpsertScanSBOM is the scanner-side write seam — even when the scanner
	// hasn't been wired to call it yet, tests can pre-seed an SBOM through it.
	// GetScanSBOM returns NotFound when the manifest has no scan row or the
	// sbom_json column is NULL.
	UpsertScanSBOM(context.Context, *UpsertScanSBOMRequest) (*emptypb.Empty, error)
	GetScanSBOM(context.Context, *GetScanSBOMRequest) (*GetScanSBOMResponse, error)
	// Vulnerability aggregate
	GetTenantVulnerabilityCount(context.Context, *GetTenantVulnerabilityCountRequest) (*VulnerabilityCountResponse, error)
	// Repository count — efficient alternative to draining ListRepositories for stats.
	CountRepositories(context.Context, *CountRepositoriesRequest) (*CountRepositoriesResponse, error)
	// Security overview (FE-API-020) — single tenant-scoped aggregate combining
	// open-vulnerability counts, scan coverage, and recency. Backs
	// GET /api/v1/security/overview on registry-management.
	GetSecurityOverview(context.Context, *GetSecurityOverviewRequest) (*SecurityOverview, error)
	// ListTenantVulnerabilities (FE-API-014) — workspace-wide vulnerabilities,
	// grouped by CVE across the latest complete scan per (tenant, repo, tag).
	// Backs GET /api/v1/security/vulnerabilities on registry-management.
	ListTenantVulnerabilities(context.Context, *ListTenantVulnerabilitiesRequest) (*ListTenantVulnerabilitiesResponse, error)
	// ListScanHistory (FE-API-015) — flat scan-history feed ordered by
	// completed_at DESC. Backs GET /api/v1/security/scans on
	// registry-management.
	ListScanHistory(context.Context, *ListScanHistoryRequest) (*ListScanHistoryResponse, error)
	// ListTenantRemediations (FE-API-017) — actionable upgrade groupings:
	// "upgrade package X from version A to version B fixes N CVEs across M
	// (repo, tag) tuples." Computed from the latest complete scan per
	// (tenant, repo, manifest_digest). Backs GET /api/v1/security/remediation
	// on registry-management.
	ListTenantRemediations(context.Context, *ListTenantRemediationsRequest) (*ListTenantRemediationsResponse, error)
	// GetTenantStorageBreakdown (FE-API-031) — top-50 repos by storage,
	// plus the tenant-wide total. Backs GET /api/v1/stats/storage on
	// registry-management.
	GetTenantStorageBreakdown(context.Context, *GetTenantStorageBreakdownRequest) (*GetTenantStorageBreakdownResponse, error)
	// GetTenantUsage (FE-API-028) — single-shot aggregate covering the
	// metadata-owned pieces of the admin tenant-detail card: storage usage and
	// cap, repository count, organisation count. Computed via one CTE so the
	// admin endpoint never fans out across multiple metadata RPCs.
	//
	// Tenants whose row does not yet exist in metadata (lazy creation via the
	// UpdateTenantQuota UPSERT pattern, FE-API-031) return all-zero counts +
	// quota_bytes=0 rather than NotFound, so the management layer can stitch
	// the response together for newly-created tenants without push activity.
	GetTenantUsage(context.Context, *GetTenantUsageRequest) (*TenantUsage, error)
	// GetRepoRetentionPolicy returns the policy attached to a repository, or
	// a typed NotFound when no policy row exists. The caller (registry-management)
	// is responsible for falling back to the org default (FE-API-039) when
	// NotFound is returned.
	GetRepoRetentionPolicy(context.Context, *GetRepoRetentionPolicyRequest) (*RetentionPolicy, error)
	// UpsertRepoRetentionPolicy creates or updates the policy. Setting
	// enabled=true with no existing preview_until causes the implementation
	// to set preview_until = now() + 24h (FE-API-038 mechanism). preview_until
	// is otherwise client-readonly — the caller cannot set it directly.
	UpsertRepoRetentionPolicy(context.Context, *UpsertRepoRetentionPolicyRequest) (*RetentionPolicy, error)
	// DeleteRepoRetentionPolicy removes the per-repo override; the repo then
	// falls back to the org default (FE-API-039).
	DeleteRepoRetentionPolicy(context.Context, *DeleteRepoRetentionPolicyRequest) (*emptypb.Empty, error)
	// ─── FE-API-038: retention policy dry-run + preview-window state ─────────
	//
	// EvaluateRetention is the read-only evaluation engine that powers both
	// the dry-run (operator inspects a candidate policy before saving) and the
	// preview-window state endpoint (UI countdown for an already-saved policy
	// sitting in its 24h preview window).
	//
	// The handler does NOT persist the candidate — it merely materialises which
	// manifests WOULD be selected for deletion (and which would be excluded by
	// a protected_tag_patterns regex) given the current manifest + tag state of
	// the repository. The executor (FE-API-040) is a separate ticket and is
	// the only path that actually deletes.
	//
	// Caps: the returned `would_delete` list is truncated to the smaller of
	// `max_delete_results` (default 1000, server cap 5000) and the full
	// candidate set. `total_count` / `total_bytes` always reflect the full set
	// (computed via SQL aggregate, not by counting the truncated slice) so the
	// UI can render "showing 1000 of 47 312 candidates" honestly.
	EvaluateRetention(context.Context, *EvaluateRetentionRequest) (*EvaluateRetentionResponse, error)
	// GetOrgRetentionPolicy returns the default retention policy attached to an
	// org, or NotFound when none exists. The shape is identical to
	// RetentionPolicy (with `org_id` populated and `repo_id` empty) so callers
	// can render both per-repo and per-org policies with the same UI code.
	GetOrgRetentionPolicy(context.Context, *GetOrgRetentionPolicyRequest) (*RetentionPolicy, error)
	// UpsertOrgRetentionPolicy creates or updates the org default policy. Same
	// preview_until semantics as UpsertRepoRetentionPolicy — the implementation
	// owns the 24h window when a default is enabled or its rules change
	// materially. The caller never sets preview_until directly.
	UpsertOrgRetentionPolicy(context.Context, *UpsertOrgRetentionPolicyRequest) (*RetentionPolicy, error)
	// DeleteOrgRetentionPolicy removes the org default. Repos that previously
	// inherited fall back to "no policy" until either a new default is set or
	// an explicit per-repo policy is created.
	DeleteOrgRetentionPolicy(context.Context, *DeleteOrgRetentionPolicyRequest) (*emptypb.Empty, error)
	// GetEffectiveRetentionPolicy resolves what policy actually applies to a
	// repository: the per-repo row if it exists, else the org default (only
	// when enabled = TRUE), else NotFound. The `inherited_from` field on the
	// response tells the BFF + UI whether to label the policy "(per-repo)" or
	// "(inherited from org default)" without a second round-trip. A disabled
	// org default deliberately does NOT propagate — falling back to a disabled
	// default would surface a confusing "no enforcement, but here's a default"
	// banner.
	GetEffectiveRetentionPolicy(context.Context, *GetEffectiveRetentionPolicyRequest) (*EffectiveRetentionPolicy, error)
	// MarkManifestRetentionPending sets retention_pending_delete_at = NOW on a
	// single manifest. Called by services/gc's retention soft-delete pass for
	// every manifest in EvaluateRetention's would_delete output.
	//
	// Idempotent: if retention_pending_delete_at is already set, the existing
	// timestamp is preserved (a re-run does NOT extend the grace window).
	MarkManifestRetentionPending(context.Context, *MarkManifestRetentionPendingRequest) (*emptypb.Empty, error)
	// ClearManifestRetentionPending unmarks a manifest queued for retention
	// deletion. Used by the "undo" UI affordance during the grace window, and
	// also for tests that need to reset state between runs.
	ClearManifestRetentionPending(context.Context, *ClearManifestRetentionPendingRequest) (*emptypb.Empty, error)
	// ListPendingDeleteManifests returns manifests whose
	// retention_pending_delete_at is older than `grace_window_secs`. Called by
	// the retention_grace executor sweep to find candidates that have ridden
	// out their grace window and are ready for hard deletion.
	//
	// tenant_id may be empty to scan all tenants (used by the cross-tenant
	// grace ticker on services/gc); a non-empty tenant_id restricts the scan.
	// The repo-blob digests needed for storage.DeleteBlob calls are NOT
	// returned by this RPC — the executor calls DeleteManifest (existing RPC)
	// which already cascades to blob cleanup via the orphan path. Keeps this
	// RPC a single-table scan instead of an N-way join against blob_links.
	ListPendingDeleteManifests(context.Context, *ListPendingDeleteManifestsRequest) (*ListPendingDeleteManifestsResponse, error)
	// ─── FUT-020: image promotion (atomic tag copy with digest verify) ─────────
	//
	// A promotion copies a source tag's manifest digest onto a destination
	// {org}/{repo}:{tag} in ONE transaction and records a `promotions` row for
	// history + audit. No blobs are copied — both tags reference the same
	// manifest digest so storage stays deduplicated.
	//
	// Errors surface as:
	//   - NotFound: source tag or destination repository does not exist.
	//   - FailedPrecondition: destination has immutable_tags AND the destination
	//     tag already exists at a DIFFERENT manifest digest (i.e. would be a
	//     move). Idempotent — a re-promotion onto the same digest succeeds and
	//     records a second promotions row for audit continuity.
	PromoteTag(context.Context, *PromoteTagRequest) (*Promotion, error)
	ListPromotions(context.Context, *ListPromotionsRequest) (*ListPromotionsResponse, error)
	// LookupOrgIDByName resolves an org name to its UUID within a tenant.
	// Read-only — unlike the repository-internal GetOrCreateOrganization
	// which has insert semantics, this RPC returns NotFound when the org
	// does not exist. Added in FE-API-039 so the management BFF can map
	// /api/v1/orgs/{org}/policies/retention URLs (which carry the org name)
	// to the org_id required by the per-org retention RPCs without an
	// unintended side-effect.
	LookupOrgIDByName(context.Context, *LookupOrgIDByNameRequest) (*LookupOrgIDByNameResponse, error)
	// ─── FUT-023: ephemeral PR-scoped registries (Phase 1) ─────────────────────
	//
	// A GitHub PR webhook drives create/promote/delete of a per-PR org
	// namespace. GetPRRegistryConfig / PutPRRegistryConfig manage the
	// per-tenant enable flag + (write-only) webhook secret + promote target.
	// HandlePREvent is the webhook-processing seam: it verifies the
	// X-Hub-Signature-256 HMAC against the sealed secret, parses the event,
	// and provisions / promotes / tears down the PR namespace, returning an
	// Outcome. ListPRNamespaces surfaces the live + torn-down namespaces for
	// the dashboard. DeleteOrganization is the teardown primitive HandlePREvent
	// uses to drop a PR org namespace (and is exposed for manual cleanup).
	GetPRRegistryConfig(context.Context, *GetPRRegistryConfigRequest) (*PRRegistryConfig, error)
	PutPRRegistryConfig(context.Context, *PutPRRegistryConfigRequest) (*PRRegistryConfig, error)
	HandlePREvent(context.Context, *HandlePREventRequest) (*HandlePREventResponse, error)
	ListPRNamespaces(context.Context, *ListPRNamespacesRequest) (*ListPRNamespacesResponse, error)
	DeleteOrganization(context.Context, *DeleteOrganizationRequest) (*emptypb.Empty, error)
}

